     1→import React, { useCallback, useEffect, useRef, useState } from "react";
     2→import "./myprofile.css";
     3→import { useAuth } from "../../Context/useAuth";
     4→import { Outlet, useLocation, useNavigate } from "react-router-dom";
     5→import Sidebar from "../SideBar/Sidebar";
     6→import { updateFontColor, updateProfileData } from "../../../API/Api";
     7→import { AnimatePresence } from "framer-motion";
     8→import { useQueryClient } from "@tanstack/react-query";
     9→import Editor from "../HomePage/Editor/Editor";
    10→import getCroppedImage from "../../utils/getCroppedImage";
    11→import extractDominantColors from "../../utils/extractDominantColors";
    12→import MobileNavlink from "../mobileNavLink/MobileNavLink";
    13→import MobileSidebarLink from "../MobileSidebarLink/MobileSidebarLink";
    14→import WriteJournalButton from "../WriteJournalButton/WriteJournalButton";
    15→import Loader from "../loadingComponent/BgLoader";
    16→import ProfileBackgroundPicker from "./components/ProfileBackgroundPicker";
    17→import ProfileEditModal from "./components/ProfileEditModal";
    18→import ProfileFontColorSelector from "./components/ProfileFontColorSelector";
    19→import ProfileHeroSection from "./components/ProfileHeroSection";
    20→import ProfileTabList from "./components/ProfileTabList";
    21→import { PROFILE_GRADIENTS } from "./constants/profileGradients";
    22→import { createProfileSidebarLinks } from "./constants/profileSidebarLinks";
    23→import { PROFILE_TABS } from "./constants/profileTabs";
    24→
    25→const MyProfile = () => {
    26→    const { user, session, isLoading, notifCount, loading } = useAuth();
    27→
    28→    const userData = user?.userData?.[0];
    29→
    30→    const [showMobileSideBar, setShowMobileSideBar] = useState(false);
    31→
    32→    const [showProfileEditor, setShowProfileEditor] = useState(false);
    33→    const [editImagePreview, setEditImagePreview] = useState("");
    34→    const [profileEditAvatar, setProfileEditAvatar] = useState(null);
    35→    const [profileEditName, setProfileEditName] = useState("");
    36→    const [profileEditBio, setProfileEditBio] = useState("");
    37→
    38→    const [showEditor, setShowEditor] = useState(false);
    39→    const [showBgPicker, setShowBgPicker] = useState(false);
    40→
    41→    const [imageSrc, setImageSrc] = useState(null);
    42→    const [crop, setCrop] = useState({ x: 0, y: 0 });
    43→    const [zoom, setZoom] = useState(1);
    44→    const [croppedAreaPixels, setCropAreaPixels] = useState(null);
    45→    const [gradientPicked, setGradientPicked] = useState(null);
    46→    const [croppedImage, setCroppedImage] = useState({});
    47→
    48→    const [showFontColorSelector, setShowFontColorSelector] = useState(false);
    49→    const [fontColor, setFontColor] = useState("");
    50→
    51→    const inputRef = useRef();
    52→    const bgInputRef = useRef();
    53→    const fontColorInputRef = useRef();
    54→
    55→    const [dominantColors, setDominantColors] = useState("#ffffffff");
    56→    const [secondaryColors, setSecondaryColors] = useState("#ffffffff");
    57→
    58→    const [isUpdatingFont, setIsUpdatingFont] = useState(false);
    59→    const [isUpdatingProfileConfig, setIsUpdatingProfileConfig] = useState(false);
    60→    const [isSavingProfile, setIsSavingProfile] = useState(false);
    61→
    62→    const navigate = useNavigate();
    63→    const navigatePath = (path) => {
    64→        return navigate(path);
    65→    };
    66→    const location = useLocation();
    67→
    68→    const queryClient = useQueryClient();
    69→
    70→    const links = createProfileSidebarLinks({
    71→        location,
    72→        navigatePath,
    73→        navigate,
    74→        notifCount,
    75→        setShowEditor,
    76→    });
    77→    const gradients = PROFILE_GRADIENTS;
    78→    const tablists = PROFILE_TABS;
    79→
    80→    useEffect(() => {
    81→        if (userData?.background) {
    82→            const backgroundImage = userData?.background;
    83→            setCroppedImage(backgroundImage);
    84→            setFontColor(userData?.profile_font_color);
    85→        }
    86→    }, [user, userData]);
    87→
    88→    const opendRichTextEditor = () => {
    89→        setShowEditor(true);
    90→    };
    91→
    92→    const handleClickOpenSidebar = () => {
    93→        setShowMobileSideBar(!showMobileSideBar);
    94→    };
    95→
    96→    const handleCloseSidebar = () => {
    97→        setShowMobileSideBar(false);
    98→    };
    99→
   100→    const handleClickEdit = (e) => {
   101→        e.stopPropagation();
   102→        setShowFontColorSelector(false);
   103→        setEditImagePreview(userData?.image_url);
   104→        setProfileEditName(userData?.name);
   105→        setProfileEditBio(userData?.bio);
   106→        setShowProfileEditor(true);
   107→    };
   108→
   109→    const closeEditor = (e) => {
   110→        e.stopPropagation();
   111→        setEditImagePreview("");
   112→        handleHideGradientPicker(e);
   113→        setImageSrc(null);
   114→        setProfileEditAvatar(null);
   115→        setShowProfileEditor(false);
   116→    };
   117→
   118→    const handleCloseRichTextEditor = useCallback(() => {
   119→        setShowEditor(false);
   120→    }, []);
   121→
   122→    const handleImageOnChange = (e) => {
   123→        const file = e.target.files[0];
   124→        setProfileEditAvatar(file);
   125→        if (file) {
   126→            setProfileEditAvatar(file);
   127→            const reader = new FileReader();
   128→            reader.onloadend = () => {
   129→                setEditImagePreview(reader.result);
   130→            };
   131→
   132→            reader.readAsDataURL(file);
   133→        } else {
   134→            setEditImagePreview("");
   135→        }
   136→    };
   137→
   138→    const insertImageFromFile = (e) => {
   139→        e.stopPropagation();
   140→        if (inputRef.current) {
   141→            inputRef.current.click();
   142→        }
   143→    };
   144→
   145→    const handleShowGradientPicker = (e) => {
   146→        e.stopPropagation();
   147→        setShowBgPicker(true);
   148→    };
   149→
   150→    const handleHideGradientPicker = (e) => {
   151→        e.stopPropagation();
   152→        setShowBgPicker(false);
   153→        setCroppedImage(userData?.background);
   154→        setImageSrc(null);
   155→        setGradientPicked(null);
   156→    };
   157→
   158→    const handleSaveProfileEdit = async () => {
   159→        setIsSavingProfile(true);
   160→        const data = {
   161→            name: profileEditName,
   162→            image: profileEditAvatar,
   163→            bio: profileEditBio,
   164→            profileBg: croppedImage,
   165→            dominantColors: dominantColors,
   166→            secondaryColors: secondaryColors,
   167→        };
   168→
   169→        try {
   170→            const formdata = new FormData();
   171→            Object.entries(data).forEach(([key, value]) => {
   172→                if (value === undefined || value === null) {
   173→                    return;
   174→                }
   175→                if (typeof value === "object" && value !== null && !(value instanceof File)) {
   176→                    formdata.append(key, JSON.stringify(value));
   177→                    return;
   178→                }
   179→
   180→                formdata.append(key, value);
   181→            });
   182→
   183→            await updateProfileData(formdata, session?.access_token);
   184→        } catch {
   185→            throw new Error("error saving update");
   186→        } finally {
   187→            setIsSavingProfile(false);
   188→            setProfileEditAvatar(null);
   189→            queryClient.invalidateQueries({ queryKey: ["userData"] });
   190→            setShowProfileEditor(false);
   191→        }
   192→    };
   193→
   194→    const handleSaveProfileConfig = async () => {
   195→        try {
   196→            setIsUpdatingProfileConfig(true);
   197→            if (imageSrc) {
   198→                const croppedImageUrl = await getCroppedImage(imageSrc, croppedAreaPixels, userData.id);
   199→                if (croppedImageUrl) {
   200→                    setCroppedImage({
   201→                        backgroundImage: `url(${croppedImageUrl?.url})`,
   202→                        backgroundSize: "cover",
   203→                        backgroundPosition: "center",
   204→                        backgroundRepeat: "no-repeat",
   205→                    });
   206→                }
   207→            } else if (gradientPicked) {
   208→                setCroppedImage(gradientPicked);
   209→            }
   210→        } catch {
   211→            throw new Error("error updating profile");
   212→        } finally {
   213→            setIsUpdatingProfileConfig(false);
   214→            setGradientPicked(null);
   215→            setImageSrc(null);
   216→            setShowBgPicker(false);
   217→            queryClient.invalidateQueries({ queryKey: ["userData"] });
   218→        }
   219→    };
   220→
   221→    const handleRemoveBgPreview = () => {
   222→        setImageSrc(null);
   223→    };
   224→
   225→    const handleSelectGradient = useCallback((gradient) => {
   226→        setCroppedImage(null);
   227→        setImageSrc(null);
   228→        setGradientPicked(gradient);
   229→    }, []);
   230→
   231→    const handleInsertBgImage = (e) => {
   232→        e.stopPropagation();
   233→        if (bgInputRef.current) {
   234→            bgInputRef.current.value = "";
   235→            bgInputRef.current.click();
   236→        }
   237→    };
   238→
   239→    const handleBgOnchange = (e) => {
   240→        const file = e.target.files[0];
   241→        if (file) {
   242→            const reader = new FileReader();
   243→            reader.onloadend = () => {
   244→                const img = new Image();
   245→                img.crossOrigin = "anonymous";
   246→
   247→                img.src = reader.result;
   248→
   249→                img.onload = () => {
   250→                    const colors = extractDominantColors(img);
   251→                    setDominantColors(colors.primary);
   252→                    setSecondaryColors(colors.secondary);
   253→                };
   254→
   255→                setImageSrc(reader.result);
   256→            };
   257→
   258→            reader.readAsDataURL(file);
   259→        } else {
   260→            return setGradientPicked({});
   261→        }
   262→    };
   263→
   264→    const handleClickFontColorSelector = (e) => {
   265→        e.stopPropagation();
   266→        setShowFontColorSelector(true);
   267→    };
   268→
   269→    const handleClickInputColor = () => {
   270→        if (fontColorInputRef.current) {
   271→            fontColorInputRef.current.click();
   272→        }
   273→    };
   274→
   275→    const handleClickSaveFontColor = async () => {
   276→        setIsUpdatingFont(true);
   277→        const formdata = new FormData();
   278→        formdata.append("fontColor", fontColor);
   279→        try {
   280→            await updateFontColor(session?.access_token, formdata);
   281→            queryClient.invalidateQueries({ queryKey: ["userData"] });
   282→        } catch {
   283→            throw new Error("error updating font");
   284→        } finally {
   285→            setIsUpdatingFont(false);
   286→            setShowFontColorSelector(false);
   287→        }
   288→    };
   289→
   290→    const hancleClickCancelFontSelect = () => {
   291→        setShowFontColorSelector(false);
   292→        setFontColor("");
   293→    };
   294→
   295→    useEffect(() => {
   296→        if (!session && !loading) {
   297→            return navigate("/login");
   298→        }
   299→    }, [session, loading, navigate]);
   300→
   301→    if (isLoading) {
   302→        return <Loader />;
   303→    }
   304→
   305→    return (
   306→        <>
   307→            <ProfileFontColorSelector
   308→                show={showFontColorSelector}
   309→                fontColor={fontColor}
   310→                fontColorInputRef={fontColorInputRef}
   311→                setFontColor={setFontColor}
   312→                handleClickInputColor={handleClickInputColor}
   313→                hancleClickCancelFontSelect={hancleClickCancelFontSelect}
   314→                handleClickSaveFontColor={handleClickSaveFontColor}
   315→                isUpdatingFont={isUpdatingFont}
   316→            />
   317→            <ProfileBackgroundPicker
   318→                show={showBgPicker}
   319→                handleBgOnchange={handleBgOnchange}
   320→                bgInputRef={bgInputRef}
   321→                gradients={gradients}
   322→                handleSelectGradient={handleSelectGradient}
   323→                handleInsertBgImage={handleInsertBgImage}
   324→                imageSrc={imageSrc}
   325→                crop={crop}
   326→                zoom={zoom}
   327→                setCrop={setCrop}
   328→                setZoom={setZoom}
   329→                setCropAreaPixels={setCropAreaPixels}
   330→                handleRemoveBgPreview={handleRemoveBgPreview}
   331→                handleHideGradientPicker={handleHideGradientPicker}
   332→                handleSaveProfileConfig={handleSaveProfileConfig}
   333→                isUpdatingProfileConfig={isUpdatingProfileConfig}
   334→            />
   335→            <AnimatePresence>
   336→                <ProfileEditModal
   337→                    showProfileEditor={showProfileEditor}
   338→                    closeEditor={closeEditor}
   339→                    croppedImage={croppedImage}
   340→                    gradientPicked={gradientPicked}
   341→                    insertImageFromFile={insertImageFromFile}
   342→                    handleImageOnChange={handleImageOnChange}
   343→                    inputRef={inputRef}
   344→                    editImagePreview={editImagePreview}
   345→                    userData={userData}
   346→                    handleShowGradientPicker={handleShowGradientPicker}
   347→                    profileEditName={profileEditName}
   348→                    setProfileEditName={setProfileEditName}
   349→                    profileEditBio={profileEditBio}
   350→                    setProfileEditBio={setProfileEditBio}
   351→                    handleSaveProfileEdit={handleSaveProfileEdit}
   352→                    isSavingProfile={isSavingProfile}
   353→                />
   354→
   355→                {showEditor && <Editor key={"main-editor"} onClose={handleCloseRichTextEditor} />}
   356→
   357→                <div
   358→                    className="profile-parent-container"
   359→                    style={croppedImage ? { background: `linear-gradient(135deg, ${dominantColors}0%, ${secondaryColors} 100%)` } : gradientPicked}
   360→                >
   361→                    {gradientPicked && <div className="blurred-gradient-bg" style={gradientPicked} />}
   362→
   363→                    {croppedImage && <div style={croppedImage} className="blurred-img-bg" />}
   364→
   365→                    <div className="side-bar-holder-container">
   366→                        <Sidebar links={links} />
   367→                    </div>
   368→
   369→                    <div style={{ color: fontColor || userData?.profile_font_color }} className="profile-center-bar-container">
   370→                        <ProfileHeroSection
   371→                            userData={userData}
   372→                            user={user}
   373→                            fontColor={fontColor}
   374→                            handleClickEdit={handleClickEdit}
   375→                            handleClickFontColorSelector={handleClickFontColorSelector}
   376→                            croppedImage={croppedImage}
   377→                            gradientPicked={gradientPicked}
   378→                        />
   379→
   380→                        <ProfileTabList tablists={tablists} navigate={navigate} location={location} />
   381→
   382→                        <Outlet />
   383→                    </div>
   384→
   385→                    <div className="profile-sidebar-right-holder-container">{/* Log out */}</div>
   386→
   387→                    {showMobileSideBar && <MobileSidebarLink onclose={handleCloseSidebar} />}
   388→
   389→                    <MobileNavlink clickOpenSidebar={handleClickOpenSidebar} />
   390→                    <WriteJournalButton onOpen={opendRichTextEditor} />
   391→                </div>
   392→            </AnimatePresence>
   393→        </>
   394→    );
   395→};
   396→
   397→export default MyProfile;
   398→

