     3→const ProfileTabList = ({ tablists, navigate, location }) => {
     4→    return (
     5→        <div className="my-profile-tablist">
     6→            {tablists.map((tab, index) => (
     7→                <div onClick={() => navigate(tab.path)} className={"tab-container"} key={index}>
     8→                    {tab.label}
     9→                    <div className={location.pathname === tab.path ? "tab-indicator" : ""}></div>
    10→                </div>
    11→            ))}
    12→        </div>
    13→    );
    14→};
    15→
    16→export default ProfileTabList;
