     1→import React from "react";
     2→import { AnimatePresence, motion as Motion } from "framer-motion";
     3→import { BarLoader } from "react-spinners";
     4→import Cropper from "react-easy-crop";
     5→
     6→const ProfileBackgroundPicker = ({
     7→    show,
     8→    handleBgOnchange,
     9→    bgInputRef,
    10→    gradients,
    11→    handleSelectGradient,
    12→    handleInsertBgImage,
    13→    imageSrc,
    14→    crop,
    15→    zoom,
    16→    setCrop,
    17→    setZoom,
    18→    setCropAreaPixels,
    19→    handleRemoveBgPreview,
    20→    handleHideGradientPicker,
    21→    handleSaveProfileConfig,
    22→    isUpdatingProfileConfig,
    23→}) => {
    24→    if (!show) {
    25→        return null;
    26→    }
    27→
    28→    return (
    29→        <AnimatePresence>
    30→            <Motion.div
    31→                initial={{ opacity: 0 }}
    32→                animate={{ opacity: 1 }}
    33→                exit={{ opacity: 0 }}
    34→                transition={{ type: "spring", stiffness: 250, damping: 25 }}
    35→                className="profile-bg-picker-container"
    36→            >
    37→                <div className="profile-bg-picker-header">Pick a gradient or add image</div>
    38→
    39→                <input
    40→                    onChange={(e) => handleBgOnchange(e)}
    41→                    style={{ display: "none" }}
    42→                    ref={bgInputRef}
    43→                    type="file"
    44→                    accept="image/*"
    45→                />
    46→
    47→                <div className="profile-bg-color-palette">
    48→                    {gradients.map((gradient, index) => (
    49→                        <div
    50→                            onClick={() => handleSelectGradient(gradient.style)}
    51→                            key={index}
    52→                            className="gradient-box"
    53→                            style={gradient.style}
    54→                        ></div>
    55→                    ))}
    56→                </div>
    57→
    58→                <div className="profile-bg-preview">
    59→                    <div onClick={(e) => handleInsertBgImage(e)} className="add-bgImage-bttn">
    60→                        <svg
    61→                            xmlns="http://www.w3.org/2000/svg"
    62→                            height="50px"
    63→                            viewBox="0 -960 960 960"
    64→                            width="50px"
    65→                            fill="currentColor"
    66→                        >
    67→                            <path d="M480-480ZM200-120q-33 0-56.5-23.5T120-200v-560q0-33 23.5-56.5T200-840h320v80H200v560h560v-320h80v320q0 33-23.5 56.5T760-120H200Zm40-160h480L570-480 450-320l-90-120-120 160Zm440-320v-80h-80v-80h80v-80h80v80h80v80h-80v80h-80Z" />
    68→                        </svg>
    69→                    </div>
    70→                    {imageSrc && (
    71→                        <>
    72→                            <Cropper
    73→                                image={imageSrc}
    74→                                crop={crop}
    75→                                zoom={zoom}
    76→                                aspect={16 / 9}
    77→                                onCropChange={setCrop}
    78→                                onZoomChange={setZoom}
    79→                                onCropComplete={(_, croppedPixels) => setCropAreaPixels(croppedPixels)}
    80→                            />
    81→                            <div className="controls">
    82→                                <input
    83→                                    type="range"
    84→                                    min={1}
    85→                                    max={3}
    86→                                    step={0.1}
    87→                                    value={zoom}
    88→                                    onChange={(e) => setZoom(e.target.value)}
    89→                                />
    90→                            </div>
    91→                            <div onClick={() => handleRemoveBgPreview()} className="remove-bg-preview">
    92→                                <svg
    93→                                    xmlns="http://www.w3.org/2000/svg"
    94→                                    height="24px"
    95→                                    viewBox="0 -960 960 960"
    96→                                    width="24px"
    97→                                    fill="currentColor"
    98→                                >
    99→                                    <path d="m336-280-56-56 144-144-144-143 56-56 144 144 143-144 56 56-144 143 144 144-56 56-143-144-144 144Z" />
   100→                                </svg>
   101→                            </div>
   102→                        </>
   103→                    )}
   104→                </div>
   105→
   106→                <div className="canvel-save-container">
   107→                    <div onClick={(e) => handleHideGradientPicker(e)} className="cancel-button">
   108→                        cancel
   109→                    </div>
   110→                    <div onClick={() => handleSaveProfileConfig()} className="save-button">
   111→                        save
   112→                    </div>
   113→                </div>
   114→
   115→                {isUpdatingProfileConfig && (
   116→                    <BarLoader
   117→                        loading={isUpdatingProfileConfig}
   118→                        width={"100%"}
   119→                        color="rgb(40, 115, 255)"
   120→                        speedMultiplier={0.7}
   121→                    />
   122→                )}
   123→            </Motion.div>
   124→        </AnimatePresence>
   125→    );
   126→};
   127→
   128→export default ProfileBackgroundPicker;
   129→

