     1→import React from "react";
     2→import { AnimatePresence, motion as Motion } from "framer-motion";
     3→import { BarLoader } from "react-spinners";
     4→
     5→const ProfileFontColorSelector = ({
     6→    show,
     7→    fontColor,
     8→    fontColorInputRef,
     9→    setFontColor,
    10→    handleClickInputColor,
    11→    hancleClickCancelFontSelect,
    12→    handleClickSaveFontColor,
    13→    isUpdatingFont,
    14→}) => {
    15→    if (!show) {
    16→        return null;
    17→    }
    18→
    19→    return (
    20→        <AnimatePresence>
    21→            <Motion.div
    22→                className="font-selector-container"
    23→                initial={{ scale: 0, opacity: 0.8 }}
    24→                animate={{ scale: 1, opacity: 1 }}
    25→                exit={{ scale: 0.8, opacity: 0 }}
    26→                transition={{ type: "spring", stiffness: 250, damping: 25 }}
    27→            >
    28→                <div
    29→                    onClick={() => handleClickInputColor()}
    30→                    style={{ background: `${fontColor}` }}
    31→                    className="input-color"
    32→                ></div>
    33→                <input
    34→                    ref={fontColorInputRef}
    35→                    value={fontColor}
    36→                    onChange={(e) => setFontColor(e.target.value)}
    37→                    style={{ display: "none" }}
    38→                    type="color"
    39→                />
    40→                <div className="save-font-color-bttn-container">
    41→                    <div className="cancel-button" onClick={() => hancleClickCancelFontSelect()}>
    42→                        Cancel
    43→                    </div>
    44→                    <div className="save-button" onClick={() => handleClickSaveFontColor()}>
    45→                        Save
    46→                    </div>
    47→                </div>
    48→
    49→                {isUpdatingFont && (
    50→                    <BarLoader
    51→                        loading={isUpdatingFont}
    52→                        width={"100%"}
    53→                        color="rgb(40, 115, 255)"
    54→                        speedMultiplier={0.7}
    55→                    />
    56→                )}
    57→            </Motion.div>
    58→        </AnimatePresence>
    59→    );
    60→};
    61→
    62→export default ProfileFontColorSelector;
    63→

