     2→import supabase from "./supabaseClient";
     3→const BASE_URL = import.meta.env.VITE_BACKEND_URL;
     4→
     5→const getCroppedImage = async (imageSrc, crop, userId) => {
     6→    if(!imageSrc || !crop){
     7→        console.warn('getCroppedImage called without valid image source or crop data')
     8→        return null
     9→    }
    10→    const image = new Image();
    11→    image.src = imageSrc;
    12→    
    13→    await new Promise((resolve, reject) => {
    14→        image.onload = resolve;
    15→        image.onerror = reject;
    16→    });
    17→
    18→    const canvas = document.createElement('canvas');
    19→    const ctx = canvas.getContext('2d');
    20→
    21→    const scaleX = image.naturalWidth / image.width;
    22→    const scaleY = image.naturalHeight / image.height;
    23→
    24→    canvas.width = crop.width;
    25→    canvas.height = crop.height;
    26→
    27→    ctx.drawImage(
    28→        image,
    29→        crop.x * scaleX,
    30→        crop.y * scaleY,
    31→        crop.width * scaleX,
    32→        crop.height * scaleY,
    33→        0,
    34→        0,
    35→        crop.width,
    36→        crop.height
    37→    );
    38→
    39→    // convert to dataURL and file
    40→    return new Promise((resolve) => {
    41→    canvas.toBlob(async(blob) => {
    42→        if (!blob) {
    43→            console.error("Canvas toBlob failed");
    44→            resolve(null);
    45→            return;
    46→        }
    47→
    48→        const formdata = new FormData();
    49→        formdata.append('image', blob);
    50→        formdata.append('userId', userId)
    51→
    52→        try {
    53→            const response = await fetch(`${BASE_URL}/uploadBackground`, {
    54→                method: 'POST',
    55→                body: formdata,
    56→            })
    57→            if(!response.ok){
    58→                throw new Error('Upload failed');
    59→            }
    60→            const {data} = await response.json();
    61→
    62→            const url = data;
    63→            const file = new File([blob], 'cropped-image.jpg', {type: 'image/jpeg'});
    64→
    65→            resolve({
    66→                url: url,
    67→                file: file,
    68→            });
    69→
    70→        } catch (error) {
    71→            console.error('Error uploading to server:', error);
    72→            resolve(null);
    73→        }
    74→        }, "image/jpeg", 0.9);
    75→    });
    76→};
    77→
    78→export default getCroppedImage;

