     1→const extractDominantColors = (imgElement) =>{
     2→    const canvas = document.createElement('canvas');
     3→    const ctx = canvas.getContext('2d', { willReadFrequently: true });
     4→
     5→    const size = 50;
     6→    canvas.width = size;
     7→    canvas.height = size;
     8→
     9→    ctx.drawImage(imgElement, 0, 0, size, size);
    10→
    11→    try {
    12→        const imageData = ctx.getImageData(0, 0, size, size);
    13→        const data = imageData.data;
    14→
    15→        const colorMap = {};
    16→
    17→        for(let i = 0; i < data.length; i += 4){
    18→            const r = Math.floor(data[i] / 10) * 10;
    19→            const g = Math.floor(data[i + 1] / 10) * 10;
    20→            const b = Math.floor(data[i + 2] / 10) * 10;
    21→            const a = data[i + 3];
    22→            
    23→            if(a < 125) continue;
    24→
    25→            const key = `${r}, ${g}, ${b}`;;
    26→            colorMap[key] = (colorMap[key] || 0) + 1
    27→        }
    28→
    29→        const sortedColors = Object.entries(colorMap)
    30→        .sort((a, b) => b[1] - a[1])
    31→        .slice(0, 2);
    32→
    33→        if(sortedColors.length > 0){
    34→            const [r1, g1, b1] = sortedColors[0][0].split(',').map(Number);
    35→            const primary = `rgb(${r1}, ${g1}, ${b1})`;
    36→
    37→            let secondary = primary;
    38→            if (sortedColors.length > 1) {
    39→                const [r2, g2, b2] = sortedColors[1][0].split(',').map(Number);
    40→                secondary = `rgb(${r2}, ${g2}, ${b2})`;
    41→            }
    42→
    43→            return {primary, secondary};
    44→        }
    45→
    46→        return { primary: '#ffffffff', secondary: '#ffffffff' };
    47→    } catch (error) {
    48→        console.error('Error extracting color:', e);
    49→        return { primary: '#ffffffff' , secondary: '#ffffffff'  };
    50→    }
    51→}
    52→
    53→export default extractDominantColors;

